sql:
SELECT COUNT(*) AS metropolis_count
FROM locations
WHERE population > 1000000;

SELECT l.location_name
FROM locations l
JOIN data_values dv ON l.location_id = dv.location_id
WHERE dv.data_id IN (
    SELECT data_id
    FROM access_logs
    WHERE user_id = 1 AND access_date = (
        SELECT MAX(access_date) FROM access_logs WHERE user_id = 1
    )
);

SELECT data_id 
FROM data_values 
WHERE data_id = 1;

SELECT sex_id, sex_name
FROM sexes
WHERE sex_name = 'Female';

SELECT COUNT(*)
FROM data_values
WHERE data_id IN (SELECT data_id FROM data_collections_join);

SELECT val
FROM data_values
WHERE location_id = (SELECT location_id FROM locations ORDER BY population DESC LIMIT 1);
